// =============================================================
// Validate Auth — extract and validate webhook payload
// =============================================================
// Validates Bearer token, extracts workflowId/tenantId/triggerPayload.
// NO Supabase calls — those are handled by native Supabase Get nodes.
// =============================================================

const Sentry = require('@sentry/node');

try {
  // --- Auth: validate shared secret ---
  const expectedSecret = $env.ORCHESTRATOR_WEBHOOK_SECRET;
  if (!expectedSecret) {
    throw new Error('ORCHESTRATOR_WEBHOOK_SECRET not configured in n8n environment');
  }

  const webhookData = $('Webhook').first().json;
  const authHeader = webhookData.headers?.authorization || webhookData.headers?.Authorization;
  if (!authHeader || authHeader !== `Bearer ${expectedSecret}`) {
    throw new Error('Unauthorized: invalid or missing Bearer token');
  }

  const { workflowId, triggerPayload, tenantId } = webhookData.body;

  if (!workflowId || !tenantId) {
    throw new Error('Missing required fields: workflowId and tenantId');
  }

  return {
    json: {
      workflowId,
      tenantId,
      triggerPayload: triggerPayload || {},
    }
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// =============================================================
// Fetch and Initialize Execution
// =============================================================
// Fetches workflow, steps, edges from Supabase inline.
// Then: validates, filters trigger steps, circular protection,
// creates execution + step execution records, topological sort,
// builds trigger context, returns sorted step list.
// =============================================================

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// ---- Supabase helper (native https, no SDK) ----

async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': method === 'POST' ? 'return=representation' : 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          if (res.statusCode >= 400) {
            reject(new Error(`Supabase ${method} ${path} returned ${res.statusCode}: ${data}`));
          } else {
            resolve(parsed);
          }
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// ---- Topological sort (Kahn's algorithm) ----

function topologicalSort(steps, edges) {
  const stepMap = new Map(steps.map(s => [s.id, s]));
  const inDegree = new Map();
  const adjacency = new Map();
  for (const step of steps) {
    inDegree.set(step.id, 0);
    adjacency.set(step.id, []);
  }
  for (const edge of edges) {
    if (!stepMap.has(edge.source_step_id) || !stepMap.has(edge.target_step_id)) continue;
    adjacency.get(edge.source_step_id).push(edge.target_step_id);
    inDegree.set(edge.target_step_id, (inDegree.get(edge.target_step_id) || 0) + 1);
  }
  const queue = [];
  for (const [id, degree] of inDegree) {
    if (degree === 0) queue.push(id);
  }
  const sorted = [];
  while (queue.length > 0) {
    const current = queue.shift();
    const step = stepMap.get(current);
    if (step) sorted.push(step);
    for (const neighbor of (adjacency.get(current) || [])) {
      const newDeg = (inDegree.get(neighbor) || 1) - 1;
      inDegree.set(neighbor, newDeg);
      if (newDeg === 0) queue.push(neighbor);
    }
  }
  if (sorted.length !== steps.length) {
    throw new Error(`Workflow graph contains a cycle. Sorted ${sorted.length} of ${steps.length} steps.`);
  }
  return sorted;
}

// ---- Build trigger context ----

function buildTriggerContext(triggerType, payload) {
  // Universal pass-through — initial variableContext = caller payload + trigger_type.
  // Triggers carry only the data the caller chose to send. Workflows that need
  // hydrated data (response, survey_link, appointment, tenant) must use explicit
  // get_* steps. The trigger_type field is set last so it overrides any caller-
  // supplied trigger_type to the canonical resolved value.
  return { ...payload, trigger_type: triggerType };
}

// ---- Main logic ----

try {
  const authData = $('Validate Auth').first().json;
  const { workflowId, tenantId, triggerPayload } = authData;

  // 1. Fetch workflow, steps, edges (parallel)
  const [workflowRows, allSteps, edges] = await Promise.all([
    supabaseRequest(`workflows?id=eq.${workflowId}&tenant_id=eq.${tenantId}&is_active=eq.true`, 'GET'),
    supabaseRequest(`workflow_steps?workflow_id=eq.${workflowId}`, 'GET'),
    supabaseRequest(`workflow_edges?workflow_id=eq.${workflowId}`, 'GET'),
  ]);

  if (!workflowRows.length) {
    throw new Error(`Workflow ${workflowId} not found or not active for tenant ${tenantId}`);
  }

  // Override with canonical tenant_id from DB — caller-supplied tenantId only used
  // for the existence/auth check above. All downstream operations use the DB value.
  const canonicalTenantId = workflowRows[0].tenant_id;

  // 2. Filter out trigger-type steps
  const TRIGGER_TYPES = ['survey_submitted', 'booking_created', 'lead_scored', 'manual', 'scheduled'];
  const steps = allSteps; // Keep trigger steps — they now execute via Trigger Handler
  const executableSteps = steps.filter(s => !TRIGGER_TYPES.includes(s.step_type));
  if (executableSteps.length === 0) {
    throw new Error(`Workflow ${workflowId} has no executable steps`);
  }

  // 3. Circular protection
  if (triggerPayload && triggerPayload.triggeringExecutionId) {
    const parentExecs = await supabaseRequest(
      `workflow_executions?id=eq.${triggerPayload.triggeringExecutionId}&limit=1`, 'GET'
    );
    if (parentExecs.length && parentExecs[0].triggering_execution_id) {
      throw new Error('Circular workflow detected: max depth (1) exceeded');
    }
  }

  // 4. Create execution record
  const executionId = uuid();
  const triggerType = triggerPayload?.trigger_type || 'manual';
  await supabaseRequest('workflow_executions', 'POST', {
    id: executionId,
    workflow_id: workflowId,
    tenant_id: canonicalTenantId,
    status: 'running',
    trigger_payload: triggerPayload || {},
    triggering_execution_id: triggerPayload?.triggeringExecutionId || null,
    started_at: new Date().toISOString(),
  });

  // 5. Create step execution records
  const stepExecRecords = steps.map(step => ({
    id: uuid(),
    execution_id: executionId,
    step_id: step.id,
    status: 'pending',
    started_at: null,
    completed_at: null,
    output_payload: null,
    error_message: null,
  }));
  await supabaseRequest('workflow_step_executions', 'POST', stepExecRecords);

  const stepExecMap = {};
  for (const se of stepExecRecords) {
    stepExecMap[se.step_id] = se.id;
  }

  // 6. Topological sort
  const sortedSteps = topologicalSort(steps, edges);

  // 7. Build trigger context
  const variableContext = buildTriggerContext(triggerType, triggerPayload || {});

  // 8. Build output items for SplitInBatches
  // NOTE: State management moved to Process step subworkflow (state[executionId] pattern)
  const items = sortedSteps.map((step, index) => ({
    json: {
      currentStep: step,
      stepIndex: index,
      totalSteps: sortedSteps.length,
      currentStepExecId: stepExecMap[step.id],
      executionId,
      workflowId,
      tenantId: canonicalTenantId,
      edges,
      allStepExecRecords: stepExecRecords,
      initialVariableContext: variableContext,
    }
  }));

  Sentry.addBreadcrumb({
    message: `Orchestrator initialized: ${sortedSteps.length} steps for workflow ${workflowId}`,
    level: 'info',
  });

  return items;

} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// =============================================================
// Handle Skipped Steps + Mark Failed Execution
// =============================================================
// Reads skippedStepIds from shared state + item. Batch-PATCHes
// skipped step executions in DB. Marks execution failed if needed.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabasePatch(path, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const options = {
      hostname: match[1],
      path: match[2],
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase PATCH ${path}: ${res.statusCode} ${data}`));
        } else {
          resolve(data ? JSON.parse(data) : null);
        }
      });
    });
    req.on('error', reject);
    req.write(JSON.stringify(body));
    req.end();
  });
}

try {
  const item = $input.first().json;
  const now = new Date().toISOString();

  // Handle skipped steps from condition branching (from current iteration's item)
  const skippedStepIds = item.skippedStepIds || [];
  if (skippedStepIds.length > 0) {
    const allStepExecs = item.allStepExecRecords || [];
    for (const skipStepId of skippedStepIds) {
      const skipExec = allStepExecs.find(se => se.step_id === skipStepId);
      if (skipExec) {
        await supabasePatch(
          `workflow_step_executions?id=eq.${skipExec.id}`,
          { status: 'skipped', completed_at: now }
        );
      }
    }
  }

  // If step failed, mark execution as failed
  if (item.failed) {
    await supabasePatch(
      `workflow_executions?id=eq.${item.executionId}`,
      { status: 'failed', completed_at: now, error_message: item.failureError }
    );
  }

  // Clean up transient fields before looping back
  return {
    json: {
      ...item,
      stepResult: null,
      skippedStepIds: null,
      dbStatus: undefined,
      dbCompletedAt: undefined,
      dbOutputPayload: undefined,
      dbErrorMessage: undefined,
      alreadyPersisted: undefined,
    }
  };
} catch (err) {
  throw err;
}

// Check if execution was already marked failed — skip completion
const items = $input.all();
const lastItem = items[items.length - 1].json;

if (lastItem.failed) {
  // Already marked failed in Handle Skipped and Failed node
  return { json: { executionId: lastItem.executionId, status: 'failed', skipCompletion: true } };
}

return { json: { executionId: lastItem.executionId, status: 'completed', skipCompletion: false } };
